1	//! Bounded channel based on a preallocated array.
2	//!
3	//! This flavor has a fixed, positive capacity.
4	//!
5	//! The implementation is based on Dmitry Vyukov's bounded MPMC queue.
6	//!
7	//! Source:
8	//!   - <http://www.1024cores.net/home/lock-free-algorithms/queues/bounded-mpmc-queue>
9	//!   - <https://docs.google.com/document/d/1yIAYmbvL3JxOKOjuCyon7JhW4cSv1wy5hC0ApeGMV9s/pub>
10	
11	use alloc::boxed::Box;
12	use core::{
13	    cell::UnsafeCell,
14	    mem::MaybeUninit,
15	    ptr,
16	    sync::atomic::{self, AtomicUsize, Ordering},
17	};
18	use std::time::Instant;
19	
20	use crossbeam_utils::{Backoff, CachePadded};
21	
22	use crate::{
23	    context::Context,
24	    err::{RecvTimeoutError, SendTimeoutError, TryRecvError, TrySendError},
25	    select::{Operation, SelectHandle, Selected, Token},
26	    waker::SyncWaker,
27	};
28	
29	/// A slot in a channel.
30	struct Slot<T> {
31	    /// The current stamp.
32	    stamp: AtomicUsize,
33	
34	    /// The message in this slot. Either read out in `read` or dropped through
35	    /// `discard_all_messages`.
36	    msg: UnsafeCell<MaybeUninit<T>>,
37	}
38	
39	/// The token type for the array flavor.
40	#[derive(Debug)]
41	pub(crate) struct ArrayToken {
42	    /// Slot to read from or write to.
43	    slot: *const u8,
44	
45	    /// Stamp to store into the slot after reading or writing.
46	    stamp: usize,
47	}
48	
49	impl Default for ArrayToken {
50	    #[inline]
51	    fn default() -> Self {
52	        Self {
53	            slot: ptr::null(),
54	            stamp: 0,
55	        }
56	    }
57	}
58	
59	/// Bounded channel based on a preallocated array.
60	pub(crate) struct Channel<T> {
61	    /// The head of the channel.
62	    ///
63	    /// This value is a "stamp" consisting of an index into the buffer, a mark bit, and a lap, but
64	    /// packed into a single `usize`. The lower bits represent the index, while the upper bits
65	    /// represent the lap. The mark bit in the head is always zero.
66	    ///
67	    /// Messages are popped from the head of the channel.
68	    head: CachePadded<AtomicUsize>,
69	
70	    /// The tail of the channel.
71	    ///
72	    /// This value is a "stamp" consisting of an index into the buffer, a mark bit, and a lap, but
73	    /// packed into a single `usize`. The lower bits represent the index, while the upper bits
74	    /// represent the lap. The mark bit indicates that the channel is disconnected.
75	    ///
76	    /// Messages are pushed into the tail of the channel.
77	    tail: CachePadded<AtomicUsize>,
78	
79	    /// The buffer holding slots.
80	    buffer: Box<[Slot<T>]>,
81	
82	    /// A stamp with the value of `{ lap: 1, mark: 0, index: 0 }`.
83	    one_lap: usize,
84	
85	    /// If this bit is set in the tail, that means the channel is disconnected.
86	    mark_bit: usize,
87	
88	    /// Senders waiting while the channel is full.
89	    senders: SyncWaker,
90	
91	    /// Receivers waiting while the channel is empty and not disconnected.
92	    receivers: SyncWaker,
93	}
94	
95	impl<T> Channel<T> {
96	    /// Creates a bounded channel of capacity `cap`.
97	    pub(crate) fn with_capacity(cap: usize) -> Self {
98	        assert!(cap > 0, "capacity must be positive");
99	
100	        // Compute constants `mark_bit` and `one_lap`.
101	        let mark_bit = (cap + 1).next_power_of_two();
102	        let one_lap = mark_bit * 2;
103	
104	        // Head is initialized to `{ lap: 0, mark: 0, index: 0 }`.
105	        let head = 0;
106	        // Tail is initialized to `{ lap: 0, mark: 0, index: 0 }`.
107	        let tail = 0;
108	
109	        // Allocate a buffer of `cap` slots initialized
110	        // with stamps.
111	        let buffer: Box<[Slot<T>]> = (0..cap)
112	            .map(|i| {
113	                // Set the stamp to `{ lap: 0, mark: 0, index: i }`.
114	                Slot {
115	                    stamp: AtomicUsize::new(i),
116	                    msg: UnsafeCell::new(MaybeUninit::uninit()),
117	                }
118	            })
119	            .collect();
120	
121	        Self {
122	            buffer,
123	            one_lap,
124	            mark_bit,
125	            head: CachePadded::new(AtomicUsize::new(head)),
126	            tail: CachePadded::new(AtomicUsize::new(tail)),
127	            senders: SyncWaker::new(),
128	            receivers: SyncWaker::new(),
129	        }
130	    }
131	
132	    /// Returns a receiver handle to the channel.
133	    pub(crate) fn receiver(&self) -> Receiver<'_, T> {
134	        Receiver(self)
135	    }
136	
137	    /// Returns a sender handle to the channel.
138	    pub(crate) fn sender(&self) -> Sender<'_, T> {
139	        Sender(self)
140	    }
141	
142	    /// Attempts to reserve a slot for sending a message.
143	    fn start_send(&self, token: &mut Token) -> bool {
144	        let backoff = Backoff::new();
145	        let mut tail = self.tail.load(Ordering::Relaxed);
146	
147	        loop {
148	            // Check if the channel is disconnected.
149	            if tail & self.mark_bit != 0 {
150	                token.array.slot = ptr::null();
151	                token.array.stamp = 0;
152	                return true;
153	            }
154	
155	            // Deconstruct the tail.
156	            let index = tail & (self.mark_bit - 1);
157	            let lap = tail & !(self.one_lap - 1);
158	
159	            // Inspect the corresponding slot.
160	            debug_assert!(index < self.buffer.len());
161	            let slot = unsafe { self.buffer.get_unchecked(index) };
162	            let stamp = slot.stamp.load(Ordering::Acquire);
163	
164	            // If the tail and the stamp match, we may attempt to push.
165	            if tail == stamp {
166	                let new_tail = if index + 1 < self.cap() {
167	                    // Same lap, incremented index.
168	                    // Set to `{ lap: lap, mark: 0, index: index + 1 }`.
169	                    tail + 1
170	                } else {
171	                    // One lap forward, index wraps around to zero.
172	                    // Set to `{ lap: lap.wrapping_add(1), mark: 0, index: 0 }`.
173	                    lap.wrapping_add(self.one_lap)
174	                };
175	
176	                // Try moving the tail.
177	                match self.tail.compare_exchange_weak(
178	                    tail,
179	                    new_tail,
180	                    Ordering::SeqCst,
181	                    Ordering::Relaxed,
182	                ) {
183	                    Ok(_) => {
184	                        // Prepare the token for the follow-up call to `write`.
185	                        token.array.slot = slot as *const Slot<T> as *const u8;
186	                        token.array.stamp = tail + 1;
187	                        return true;
188	                    }
189	                    Err(t) => {
190	                        tail = t;
191	                        backoff.spin();
192	                    }
193	                }
194	            } else if stamp.wrapping_add(self.one_lap) == tail + 1 {
195	                atomic::fence(Ordering::SeqCst);
196	                let head = self.head.load(Ordering::Relaxed);
197	
198	                // If the head lags one lap behind the tail as well...
199	                if head.wrapping_add(self.one_lap) == tail {
200	                    // ...then the channel is full.
201	                    return false;
202	                }
203	
204	                backoff.spin();
205	                tail = self.tail.load(Ordering::Relaxed);
206	            } else {
207	                // Snooze because we need to wait for the stamp to get updated.
208	                backoff.snooze();
209	                tail = self.tail.load(Ordering::Relaxed);
210	            }
211	        }
212	    }
213	
214	    /// Writes a message into the channel.
215	    pub(crate) unsafe fn write(&self, token: &mut Token, msg: T) -> Result<(), T> {
216	        // If there is no slot, the channel is disconnected.
217	        if token.array.slot.is_null() {
218	            return Err(msg);
219	        }
220	
221	        let slot: &Slot<T> = unsafe { &*token.array.slot.cast::<Slot<T>>() };
222	
223	        // Write the message into the slot and update the stamp.
224	        unsafe { slot.msg.get().write(MaybeUninit::new(msg)) }
225	        slot.stamp.store(token.array.stamp, Ordering::Release);
226	
227	        // Wake a sleeping receiver.
228	        self.receivers.notify();
229	        Ok(())
230	    }
231	
232	    /// Attempts to reserve a slot for receiving a message.
233	    fn start_recv(&self, token: &mut Token) -> bool {
234	        let backoff = Backoff::new();
235	        let mut head = self.head.load(Ordering::Relaxed);
236	
237	        loop {
238	            // Deconstruct the head.
239	            let index = head & (self.mark_bit - 1);
240	            let lap = head & !(self.one_lap - 1);
241	
242	            // Inspect the corresponding slot.
243	            debug_assert!(index < self.buffer.len());
244	            let slot = unsafe { self.buffer.get_unchecked(index) };
245	            let stamp = slot.stamp.load(Ordering::Acquire);
246	
247	            // If the stamp is ahead of the head by 1, we may attempt to pop.
248	            if head + 1 == stamp {
249	                let new = if index + 1 < self.cap() {
250	                    // Same lap, incremented index.
251	                    // Set to `{ lap: lap, mark: 0, index: index + 1 }`.
252	                    head + 1
253	                } else {
254	                    // One lap forward, index wraps around to zero.
255	                    // Set to `{ lap: lap.wrapping_add(1), mark: 0, index: 0 }`.
256	                    lap.wrapping_add(self.one_lap)
257	                };
258	
259	                // Try moving the head.
260	                match self.head.compare_exchange_weak(
261	                    head,
262	                    new,
263	                    Ordering::SeqCst,
264	                    Ordering::Relaxed,
265	                ) {
266	                    Ok(_) => {
267	                        // Prepare the token for the follow-up call to `read`.
268	                        token.array.slot = slot as *const Slot<T> as *const u8;
269	                        token.array.stamp = head.wrapping_add(self.one_lap);
270	                        return true;
271	                    }
272	                    Err(h) => {
273	                        head = h;
274	                        backoff.spin();
275	                    }
276	                }
277	            } else if stamp == head {
278	                atomic::fence(Ordering::SeqCst);
279	                let tail = self.tail.load(Ordering::Relaxed);
280	
281	                // If the tail equals the head, that means the channel is empty.
282	                if (tail & !self.mark_bit) == head {
283	                    // If the channel is disconnected...
284	                    if tail & self.mark_bit != 0 {
285	                        // ...then receive an error.
286	                        token.array.slot = ptr::null();
287	                        token.array.stamp = 0;
288	                        return true;
289	                    } else {
290	                        // Otherwise, the receive operation is not ready.
291	                        return false;
292	                    }
293	                }
294	
295	                backoff.spin();
296	                head = self.head.load(Ordering::Relaxed);
297	            } else {
298	                // Snooze because we need to wait for the stamp to get updated.
299	                backoff.snooze();
300	                head = self.head.load(Ordering::Relaxed);
301	            }
302	        }
303	    }
304	
305	    /// Reads a message from the channel.
306	    pub(crate) unsafe fn read(&self, token: &mut Token) -> Result<T, ()> {
307	        if token.array.slot.is_null() {
308	            // The channel is disconnected.
309	            return Err(());
310	        }
311	
312	        let slot: &Slot<T> = unsafe { &*token.array.slot.cast::<Slot<T>>() };
313	
314	        // Read the message from the slot and update the stamp.
315	        let msg = unsafe { slot.msg.get().read().assume_init() };
316	        slot.stamp.store(token.array.stamp, Ordering::Release);
317	
318	        // Wake a sleeping sender.
319	        self.senders.notify();
320	        Ok(msg)
321	    }
322	
323	    /// Attempts to send a message into the channel.
324	    pub(crate) fn try_send(&self, msg: T) -> Result<(), TrySendError<T>> {
325	        let token = &mut Token::default();
326	        if self.start_send(token) {
327	            unsafe { self.write(token, msg).map_err(TrySendError::Disconnected) }
328	        } else {
329	            Err(TrySendError::Full(msg))
330	        }
331	    }
332	
333	    /// Sends a message into the channel.
334	    pub(crate) fn send(
335	        &self,
336	        msg: T,
337	        deadline: Option<Instant>,
338	    ) -> Result<(), SendTimeoutError<T>> {
339	        let token = &mut Token::default();
340	        loop {
341	            // Try sending a message several times.
342	            let backoff = Backoff::new();
343	            loop {
344	                if self.start_send(token) {
345	                    let res = unsafe { self.write(token, msg) };
346	                    return res.map_err(SendTimeoutError::Disconnected);
347	                }
348	
349	                if backoff.is_completed() {
350	                    break;
351	                } else {
352	                    backoff.snooze();
353	                }
354	            }
355	
356	            if let Some(d) = deadline {
357	                if Instant::now() >= d {
358	                    return Err(SendTimeoutError::Timeout(msg));
359	                }
360	            }
361	
362	            Context::with(|cx| {
363	                // Prepare for blocking until a receiver wakes us up.
364	                let oper = Operation::hook(token);
365	                self.senders.register(oper, cx);
366	
367	                // Has the channel become ready just now?
368	                if !self.is_full() || self.is_disconnected() {
369	                    let _ = cx.try_select(Selected::Aborted);
370	                }
371	
372	                // Block the current thread.
373	                let sel = cx.wait_until(deadline);
374	
375	                match sel {
376	                    Selected::Waiting => unreachable!(),
377	                    Selected::Aborted | Selected::Disconnected => {
378	                        self.senders.unregister(oper).unwrap();
379	                    }
380	                    Selected::Operation(_) => {}
381	                }
382	            });
383	        }
384	    }
385	
386	    /// Attempts to receive a message without blocking.
387	    pub(crate) fn try_recv(&self) -> Result<T, TryRecvError> {
388	        let token = &mut Token::default();
389	
390	        if self.start_recv(token) {
391	            unsafe { self.read(token).map_err(|_| TryRecvError::Disconnected) }
392	        } else {
393	            Err(TryRecvError::Empty)
394	        }
395	    }
396	
397	    /// Receives a message from the channel.
398	    pub(crate) fn recv(&self, deadline: Option<Instant>) -> Result<T, RecvTimeoutError> {
399	        let token = &mut Token::default();
400	        loop {
401	            // Try receiving a message several times.
402	            let backoff = Backoff::new();
403	            loop {
404	                if self.start_recv(token) {
405	                    let res = unsafe { self.read(token) };
406	                    return res.map_err(|_| RecvTimeoutError::Disconnected);
407	                }
408	
409	                if backoff.is_completed() {
410	                    break;
411	                } else {
412	                    backoff.snooze();
413	                }
414	            }
415	
416	            if let Some(d) = deadline {
417	                if Instant::now() >= d {
418	                    return Err(RecvTimeoutError::Timeout);
419	                }
420	            }
421	
422	            Context::with(|cx| {
423	                // Prepare for blocking until a sender wakes us up.
424	                let oper = Operation::hook(token);
425	                self.receivers.register(oper, cx);
426	
427	                // Has the channel become ready just now?
428	                if !self.is_empty() || self.is_disconnected() {
429	                    let _ = cx.try_select(Selected::Aborted);
430	                }
431	
432	                // Block the current thread.
433	                let sel = cx.wait_until(deadline);
434	
435	                match sel {
436	                    Selected::Waiting => unreachable!(),
437	                    Selected::Aborted | Selected::Disconnected => {
438	                        self.receivers.unregister(oper).unwrap();
439	                        // If the channel was disconnected, we still have to check for remaining
440	                        // messages.
441	                    }
442	                    Selected::Operation(_) => {}
443	                }
444	            });
445	        }
446	    }
447	
448	    /// Returns the current number of messages inside the channel.
449	    pub(crate) fn len(&self) -> usize {
450	        loop {
451	            // Load the tail, then load the head.
452	            let tail = self.tail.load(Ordering::SeqCst);
453	            let head = self.head.load(Ordering::SeqCst);
454	
455	            // If the tail didn't change, we've got consistent values to work with.
456	            if self.tail.load(Ordering::SeqCst) == tail {
457	                let hix = head & (self.mark_bit - 1);
458	                let tix = tail & (self.mark_bit - 1);
459	
460	                return if hix < tix {
461	                    tix - hix
462	                } else if hix > tix {
463	                    self.cap() - hix + tix
464	                } else if (tail & !self.mark_bit) == head {
465	                    0
466	                } else {
467	                    self.cap()
468	                };
469	            }
470	        }
471	    }
472	
473	    /// Returns the capacity of the channel.
474	    #[inline]
475	    fn cap(&self) -> usize {
476	        self.buffer.len()
477	    }
478	
479	    /// Returns the capacity of the channel.
480	    pub(crate) fn capacity(&self) -> Option<usize> {
481	        Some(self.cap())
482	    }
483	
484	    /// Disconnects senders and wakes up all blocked receivers.
485	    ///
486	    /// Returns `true` if this call disconnected the channel.
487	    pub(crate) fn disconnect_senders(&self) -> bool {
488	        let tail = self.tail.fetch_or(self.mark_bit, Ordering::SeqCst);
489	
490	        if tail & self.mark_bit == 0 {
491	            self.receivers.disconnect();
492	            true
493	        } else {
494	            false
495	        }
496	    }
497	
498	    /// Disconnects receivers and wakes up all blocked senders.
499	    ///
500	    /// Returns `true` if this call disconnected the channel.
501	    ///
502	    /// # Safety
503	    /// May only be called once upon dropping the last receiver. The
504	    /// destruction of all other receivers must have been observed with acquire
505	    /// ordering or stronger.
506	    pub(crate) unsafe fn disconnect_receivers(&self) -> bool {
507	        let tail = self.tail.fetch_or(self.mark_bit, Ordering::SeqCst);
508	        let disconnected = if tail & self.mark_bit == 0 {
509	            self.senders.disconnect();
510	            true
511	        } else {
512	            false
513	        };
514	
515	        unsafe { self.discard_all_messages(tail) }
516	        disconnected
517	    }
518	
519	    /// Discards all messages.
520	    ///
521	    /// `tail` should be the current (and therefore last) value of `tail`.
522	    ///
523	    /// # Panicking
524	    /// If a destructor panics, the remaining messages are leaked, matching the
525	    /// behaviour of the unbounded channel.
526	    ///
527	    /// # Safety
528	    /// This method must only be called when dropping the last receiver. The
529	    /// destruction of all other receivers must have been observed with acquire
530	    /// ordering or stronger.
531	    unsafe fn discard_all_messages(&self, tail: usize) {
532	        debug_assert!(self.is_disconnected());
533	
534	        // Only receivers modify `head`, so since we are the last one,
535	        // this value will not change and will not be observed (since
536	        // no new messages can be sent after disconnection).
537	        let mut head = self.head.load(Ordering::Relaxed);
538	        let tail = tail & !self.mark_bit;
539	
540	        let backoff = Backoff::new();
541	        loop {
542	            // Deconstruct the head.
543	            let index = head & (self.mark_bit - 1);
544	            let lap = head & !(self.one_lap - 1);
545	
546	            // Inspect the corresponding slot.
547	            debug_assert!(index < self.buffer.len());
548	            let slot = unsafe { self.buffer.get_unchecked(index) };
549	            let stamp = slot.stamp.load(Ordering::Acquire);
550	
551	            // If the stamp is ahead of the head by 1, we may drop the message.
552	            if head + 1 == stamp {
553	                head = if index + 1 < self.cap() {
554	                    // Same lap, incremented index.
555	                    // Set to `{ lap: lap, mark: 0, index: index + 1 }`.
556	                    head + 1
557	                } else {
558	                    // One lap forward, index wraps around to zero.
559	                    // Set to `{ lap: lap.wrapping_add(1), mark: 0, index: 0 }`.
560	                    lap.wrapping_add(self.one_lap)
561	                };
562	
563	                unsafe {
564	                    (*slot.msg.get()).assume_init_drop();
565	                }
566	            // If the tail equals the head, that means the channel is empty.
567	            } else if tail == head {
568	                return;
569	            // Otherwise, a sender is about to write into the slot, so we need
570	            // to wait for it to update the stamp.
571	            } else {
572	                backoff.snooze();
573	            }
574	        }
575	    }
576	
577	    /// Returns `true` if the channel is disconnected.
578	    pub(crate) fn is_disconnected(&self) -> bool {
579	        self.tail.load(Ordering::SeqCst) & self.mark_bit != 0
580	    }
581	
582	    /// Returns `true` if the channel is empty.
583	    pub(crate) fn is_empty(&self) -> bool {
584	        let head = self.head.load(Ordering::SeqCst);
585	        let tail = self.tail.load(Ordering::SeqCst);
586	
587	        // Is the tail equal to the head?
588	        //
589	        // Note: If the head changes just before we load the tail, that means there was a moment
590	        // when the channel was not empty, so it is safe to just return `false`.
591	        (tail & !self.mark_bit) == head
592	    }
593	
594	    /// Returns `true` if the channel is full.
595	    pub(crate) fn is_full(&self) -> bool {
596	        let tail = self.tail.load(Ordering::SeqCst);
597	        let head = self.head.load(Ordering::SeqCst);
598	
599	        // Is the head lagging one lap behind tail?
600	        //
601	        // Note: If the tail changes just before we load the head, that means there was a moment
602	        // when the channel was not full, so it is safe to just return `false`.
603	        head.wrapping_add(self.one_lap) == tail & !self.mark_bit
604	    }
605	}
606	
607	/// Receiver handle to a channel.
608	pub(crate) struct Receiver<'a, T>(&'a Channel<T>);
609	
610	/// Sender handle to a channel.
611	pub(crate) struct Sender<'a, T>(&'a Channel<T>);
612	
613	impl<T> SelectHandle for Receiver<'_, T> {
614	    fn try_select(&self, token: &mut Token) -> bool {
615	        self.0.start_recv(token)
616	    }
617	
618	    fn deadline(&self) -> Option<Instant> {
619	        None
620	    }
621	
622	    fn register(&self, oper: Operation, cx: &Context) -> bool {
623	        self.0.receivers.register(oper, cx);
624	        self.is_ready()
625	    }
626	
627	    fn unregister(&self, oper: Operation) {
628	        self.0.receivers.unregister(oper);
629	    }
630	
631	    fn accept(&self, token: &mut Token, _cx: &Context) -> bool {
632	        self.try_select(token)
633	    }
634	
635	    fn is_ready(&self) -> bool {
636	        !self.0.is_empty() || self.0.is_disconnected()
637	    }
638	
639	    fn watch(&self, oper: Operation, cx: &Context) -> bool {
640	        self.0.receivers.watch(oper, cx);
641	        self.is_ready()
642	    }
643	
644	    fn unwatch(&self, oper: Operation) {
645	        self.0.receivers.unwatch(oper);
646	    }
647	}
648	
649	impl<T> SelectHandle for Sender<'_, T> {
650	    fn try_select(&self, token: &mut Token) -> bool {
651	        self.0.start_send(token)
652	    }
653	
