1	//! Waking mechanism for threads blocked on channel operations.
2	
3	use alloc::vec::Vec;
4	use core::{
5	    ptr,
6	    sync::atomic::{AtomicBool, Ordering},
7	};
8	use std::thread::{self, ThreadId};
9	
10	use crate::{
11	    context::Context,
12	    select::{Operation, Selected},
13	    utils::Mutex,
14	};
15	
16	/// Represents a thread blocked on a specific channel operation.
17	pub(crate) struct Entry {
18	    /// The operation.
19	    pub(crate) oper: Operation,
20	
21	    /// Optional packet.
22	    pub(crate) packet: *mut (),
23	
24	    /// Context associated with the thread owning this operation.
25	    pub(crate) cx: Context,
26	}
27	
28	/// A queue of threads blocked on channel operations.
29	///
30	/// This data structure is used by threads to register blocking operations and get woken up once
31	/// an operation becomes ready.
32	pub(crate) struct Waker {
33	    /// A list of select operations.
34	    selectors: Vec<Entry>,
35	
36	    /// A list of operations waiting to be ready.
37	    observers: Vec<Entry>,
38	}
39	
40	impl Waker {
41	    /// Creates a new `Waker`.
42	    #[inline]
43	    pub(crate) fn new() -> Self {
44	        Self {
45	            selectors: Vec::new(),
46	            observers: Vec::new(),
47	        }
48	    }
49	
50	    /// Registers a select operation.
51	    #[inline]
52	    pub(crate) fn register(&mut self, oper: Operation, cx: &Context) {
53	        self.register_with_packet(oper, ptr::null_mut(), cx);
54	    }
55	
56	    /// Registers a select operation and a packet.
57	    #[inline]
58	    pub(crate) fn register_with_packet(&mut self, oper: Operation, packet: *mut (), cx: &Context) {
59	        self.selectors.push(Entry {
60	            oper,
61	            packet,
62	            cx: cx.clone(),
63	        });
64	    }
65	
66	    /// Unregisters a select operation.
67	    #[inline]
68	    pub(crate) fn unregister(&mut self, oper: Operation) -> Option<Entry> {
69	        if let Some((i, _)) = self
70	            .selectors
71	            .iter()
72	            .enumerate()
73	            .find(|&(_, entry)| entry.oper == oper)
74	        {
75	            let entry = self.selectors.remove(i);
76	            Some(entry)
77	        } else {
78	            None
79	        }
80	    }
81	
